<template>
	<div class="header bg-white border-b p-3 sm:p-4">
		<div class="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
			<!-- Week Navigation -->
			<div class="flex items-center gap-2 sm:gap-4">
				<button
					@click="emit('week-change', 'prev')"
					class="px-2 sm:px-3 py-1.5 sm:py-2 border rounded hover:bg-gray-50 text-sm"
				>
					←
				</button>

				<div class="text-sm sm:text-lg font-semibold whitespace-nowrap">
					{{ weekLabel }}
				</div>

				<button
					@click="emit('week-change', 'next')"
					class="px-2 sm:px-3 py-1.5 sm:py-2 border rounded hover:bg-gray-50 text-sm"
				>
					→
				</button>

				<button
					@click="emit('week-change', 'today')"
					class="px-2 sm:px-3 py-1.5 sm:py-2 bg-blue-500 text-white rounded hover:bg-blue-600 text-sm"
				>
					Today
				</button>
			</div>

			<!-- Actions -->
			<div class="flex items-center gap-2 flex-wrap">
				<label
					class="flex items-center gap-1.5 px-2 sm:px-3 py-1.5 sm:py-2 border rounded hover:bg-gray-50 text-sm cursor-pointer select-none"
				>
					<input
						type="checkbox"
						:checked="store.showWeekend"
						@change="store.toggleWeekend()"
						class="rounded border-gray-300 text-blue-500 focus:ring-blue-500"
					/>
					<span class="hidden sm:inline">Show weekend</span>
					<span class="sm:hidden">Sa/Su</span>
				</label>

				<button
					v-if="!store.isProjectUser"
					@click="emit('toggle-resource-pool')"
					class="px-2 sm:px-3 py-1.5 sm:py-2 border rounded hover:bg-gray-50 text-sm"
				>
					📊 <span class="hidden sm:inline">Resource Pool</span>
				</button>

				<button
					v-if="!store.isProjectUser"
					@click="emit('generate-timesheets')"
					class="px-2 sm:px-3 py-1.5 sm:py-2 bg-green-500 text-white rounded hover:bg-green-600 text-sm"
				>
					⏱️ <span class="hidden sm:inline">Generate Timesheets</span>
				</button>
			</div>
		</div>
	</div>
</template>

<script setup>
import { computed } from "vue";
import { useWeeklyPlanningStore } from "../../stores/weeklyPlanningStore";

const emit = defineEmits([
	"week-change",
	"filter-change",
	"toggle-resource-pool",
	"generate-timesheets",
]);
const store = useWeeklyPlanningStore();

const weekLabel = computed(() => {
	if (!store.currentWeekStart) return "";

	const start = new Date(store.currentWeekStart);
	const end = new Date(start);
	end.setDate(end.getDate() + (store.showWeekend ? 6 : 4)); // Sunday or Friday

	const options = { month: "short", day: "numeric" };
	const startYear = start.getFullYear();
	const endYear = end.getFullYear();
	const startLabel = start.toLocaleDateString("en-US", options);
	const endLabel = end.toLocaleDateString("en-US", options);

	if (startYear !== endYear) {
		return `${startLabel}, ${startYear} - ${endLabel}, ${endYear}`;
	}

	return `${startLabel} - ${endLabel}, ${startYear}`;
});
</script>
